import java.util.*;
public class KthStream {
    static class KthLargest{PriorityQueue<Integer> pq;int k;KthLargest(int k,int[] nums){this.k=k;pq=new PriorityQueue<>();for(int n:nums){pq.offer(n);if(pq.size()>k)pq.poll();}}int add(int v){pq.offer(v);if(pq.size()>k)pq.poll();return pq.peek();}}
    public static void main(String[] a){KthLargest kl=new KthLargest(3,new int[]{4,5,8,2});System.out.println(kl.add(3));System.out.println(kl.add(5));System.out.println(kl.add(10));System.out.println(kl.add(9));System.out.println("Min-heap size k — top is always kth largest. O(log k) per add.");}
}

import java.util.*;
public class MedianFinder {
    static PriorityQueue<Integer> lo,hi;
    static void init(){lo=new PriorityQueue<>(Collections.reverseOrder());hi=new PriorityQueue<>();}
    static void addNum(int n){lo.offer(n);hi.offer(lo.poll());if(hi.size()>lo.size())lo.offer(hi.poll());}
    static double findMedian(){return lo.size()>hi.size()?lo.peek():(lo.peek()+hi.peek())/2.0;}
    public static void main(String[] a){init();addNum(1);addNum(2);System.out.println(findMedian());addNum(3);System.out.println(findMedian());System.out.println("lo: max-heap lower half. hi: min-heap upper half. Balance after each insert.");}
}

import java.util.*;
public class ReorgStr {
    public static String reorganizeString(String s){
        int[] cnt=new int[26];for(char c:s.toCharArray())cnt[c-'a']++;
        PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->b[1]-a[1]);
        for(int i=0;i<26;i++)if(cnt[i]>0)pq.offer(new int[]{i,cnt[i]});
        StringBuilder sb=new StringBuilder();
        while(pq.size()>1){int[] a=pq.poll(),b=pq.poll();sb.append((char)('a'+a[0]));sb.append((char)('a'+b[0]));if(--a[1]>0)pq.offer(a);if(--b[1]>0)pq.offer(b);}
        if(!pq.isEmpty()){if(pq.peek()[1]>1)return "";sb.append((char)('a'+pq.poll()[0]));}
        return sb.toString();
    }
    public static void main(String[] a){System.out.println(reorganizeString("aab"));System.out.println(reorganizeString("aaab").isEmpty());System.out.println("Greedy: always pick two highest-frequency chars. O(n log 26)=O(n)");}
}

import java.util.*;
public class SmallestRange {
    public static int[] smallestRange(List<List<Integer>> nums){
        PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[0]-b[0]);
        int max=Integer.MIN_VALUE;
        for(int i=0;i<nums.size();i++){pq.offer(new int[]{nums.get(i).get(0),i,0});max=Math.max(max,nums.get(i).get(0));}
        int[] res={pq.peek()[0],max};
        while(true){int[] top=pq.poll();int list=top[1],idx=top[2]+1;if(idx>=nums.get(list).size())break;int v=nums.get(list).get(idx);max=Math.max(max,v);pq.offer(new int[]{v,list,idx});if(max-pq.peek()[0]<res[1]-res[0]){res[0]=pq.peek()[0];res[1]=max;}}
        return res;
    }
    public static void main(String[] a){System.out.println(Arrays.toString(smallestRange(Arrays.asList(Arrays.asList(4,10,15,24,26),Arrays.asList(0,9,12,20),Arrays.asList(5,18,22,30)))));System.out.println("[20,24] — O(n log k) min-heap maintaining one element from each list");}
}

import java.util.*;
public class IPO {
    public static int findMaximizedCapital(int k,int w,int[] profits,int[] capital){
        PriorityQueue<int[]> byCapital=new PriorityQueue<>((a,b)->a[0]-b[0]); // min-heap by capital
        PriorityQueue<Integer> byProfit=new PriorityQueue<>(Collections.reverseOrder());
        for(int i=0;i<profits.length;i++)byCapital.offer(new int[]{capital[i],profits[i]});
        for(int i=0;i<k;i++){
            while(!byCapital.isEmpty()&&byCapital.peek()[0]<=w)byProfit.offer(byCapital.poll()[1]);
            if(byProfit.isEmpty())break;w+=byProfit.poll();}
        return w;
    }
    public static void main(String[] a){System.out.println(findMaximizedCapital(2,0,new int[]{1,2,3},new int[]{0,1,1}));System.out.println(findMaximizedCapital(3,0,new int[]{1,2,3},new int[]{0,1,2}));System.out.println("Two heaps: unlock projects by capital, always pick most profitable unlocked");}
}

import java.util.*;
public class SWMedian {
    static PriorityQueue<Integer> lo=new PriorityQueue<>(Collections.reverseOrder()),hi=new PriorityQueue<>();
    static Map<Integer,Integer> lazy=new HashMap<>();
    static int loSize=0,hiSize=0;
    static void add(int n){if(!lo.isEmpty()&&n<=lo.peek()){lo.offer(n);loSize++;}else{hi.offer(n);hiSize++;}balance();}
    static void remove(int n){lazy.merge(n,1,Integer::sum);if(!lo.isEmpty()&&n<=lo.peek())loSize--;else hiSize--;balance();}
    static void balance(){if(loSize>hiSize+1){hi.offer(lo.poll());loSize--;hiSize++;}else if(hiSize>loSize){lo.offer(hi.poll());hiSize--;loSize++;}while(!lo.isEmpty()&&lazy.getOrDefault(lo.peek(),0)>0){lazy.merge(lo.peek(),-1,Integer::sum);if(lazy.get(lo.peek())==0)lazy.remove(lo.peek());lo.poll();}while(!hi.isEmpty()&&lazy.getOrDefault(hi.peek(),0)>0){lazy.merge(hi.peek(),-1,Integer::sum);if(lazy.get(hi.peek())==0)lazy.remove(hi.peek());hi.poll();}}
    static double median(){return loSize>hiSize?lo.peek():(lo.peek()+hi.peek())/2.0;}
    public static void main(String[] a){System.out.println("Sliding Window Median: two heaps + lazy deletion");System.out.println("O(n log k) — k window size");}
}

import java.util.*;
public class MergeK {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode mergeKLists(ListNode[] lists){
        PriorityQueue<ListNode> pq=new PriorityQueue<>((a,b)->a.val-b.val);
        for(ListNode l:lists)if(l!=null)pq.offer(l);
        ListNode dummy=new ListNode(0),cur=dummy;
        while(!pq.isEmpty()){cur.next=pq.poll();cur=cur.next;if(cur.next!=null)pq.offer(cur.next);}
        return dummy.next;
    }
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    static String str(ListNode h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
    public static void main(String[] a){System.out.println(str(mergeKLists(new ListNode[]{of(1,4,5),of(1,3,4),of(2,6)})));System.out.println("O(N log K) — N total nodes, K lists");}
}

import java.util.*;
public class CarPool {
    public static boolean carPooling(int[][] trips, int capacity){
        Arrays.sort(trips,(a,b)->a[1]-b[1]);
        PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[1]-b[1]); // [passengers, dropoff]
        int current=0;
        for(int[] t:trips){
            while(!pq.isEmpty()&&pq.peek()[1]<=t[1]){current-=pq.poll()[0];}
            current+=t[0];if(current>capacity)return false;pq.offer(new int[]{t[0],t[2]});}
        return true;
    }
    public static void main(String[] a){System.out.println(carPooling(new int[][]{{2,1,5},{3,3,7}},4));System.out.println(carPooling(new int[][]{{2,1,5},{3,3,7}},5));System.out.println("Sort by pickup; min-heap by dropoff; release passengers when past dropoff");}
}

import java.util.*;
public class FurthestBldg {
    public static int furthestBuilding(int[] h, int bricks, int ladders){
        PriorityQueue<Integer> pq=new PriorityQueue<>(); // min-heap of ladder uses
        for(int i=0;i<h.length-1;i++){
            int diff=h[i+1]-h[i];if(diff<=0)continue;
            pq.offer(diff);
            if(pq.size()>ladders){bricks-=pq.poll();} // use bricks on smallest climb
            if(bricks<0)return i;}
        return h.length-1;
    }
    public static void main(String[] a){System.out.println(furthestBuilding(new int[]{4,2,7,6,9,14,12},10,1));System.out.println(furthestBuilding(new int[]{4,12,2,7,3,18,20,3,19},10,2));System.out.println("Greedy: use ladders for biggest climbs; use bricks when exceeded ladders count");}
}

import java.util.*;
public class T2Synth {
    static int kthL(int[] n,int k){PriorityQueue<Integer> pq=new PriorityQueue<>();for(int x:n){pq.offer(x);if(pq.size()>k)pq.poll();}return pq.peek();}
    static int meetRooms(int[][] ivs){Arrays.sort(ivs,(a,b)->a[0]-b[0]);PriorityQueue<Integer> pq=new PriorityQueue<>();for(int[]iv:ivs){if(!pq.isEmpty()&&pq.peek()<=iv[0])pq.poll();pq.offer(iv[1]);}return pq.size();}
    static int taskS(char[] t,int n){int[]c=new int[26];for(char x:t)c[x-'A']++;int m=0;for(int x:c)m=Math.max(m,x);int cnt=0;for(int x:c)if(x==m)cnt++;return Math.max((m-1)*(n+1)+cnt,t.length);}
    public static void main(String[] a){System.out.println(kthL(new int[]{3,2,1,5,6,4},2));System.out.println(meetRooms(new int[][]{{0,30},{5,10},{15,20}}));System.out.println(taskS(new char[]{'A','A','A','B','B','B'},2));boolean ok=kthL(new int[]{3,2,1,5,6,4},2)==5&&meetRooms(new int[][]{{0,30},{5,10},{15,20}})==2&&taskS(new char[]{'A','A','A','B','B','B'},2)==8;System.out.println("All pass: "+ok);}
}

